#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);

my $log_dir = '/path/to/logs';  # Set your log directory here
my $query = CGI->new;
print $query->header;

my $filename = $query->param('logfile');

if ($filename) {
    my $filepath = "$log_dir/$filename";
    
    if (-e $filepath && -r $filepath) {
        open(my $fh, '<', $filepath) or die "Cannot open file: $!";
        print $query->start_html("Log Viewer");
        print $query->h1("Viewing Log: $filename");
        print $query->pre(do { local $/; <$fh> });
        close($fh);
        print $query->end_html;
    } else {
        print $query->h1("Error: File not found or not readable.");
    }
} else {
    print $query->h1("Error: No log file specified.");
}